const g=[{slug:"Граница тишины",title:"Граница тишины",description:"Это один человек, разорванный внутри. Он потерян, но держится за свою единственную опору — собственное пространство. Он закрывает лицо, будто боится быть увиденным настоящим. Руки — как стены, которые он строит между собой и миром. Он устал от чужих взглядов, слов и ожиданий. Ему страшно выйти наружу, но ещё страшнее — впустить кого-то внутрь..",coverImage:"/images/series/GRANICA1.jpg",works:[{slug:"Граница-2"},{slug:"Граница-3"}]},{slug:"Потерянные 10ые",title:"Потерянные 10ые",description:"В серию работ под названием «Потерянные 10ые» вошли четыре картины, связанные одной темой.  Теме главной рефлексии каждого взрослого человека. Цель, к которой каждый из нас так стремился-стать взрослым, достигнута. Ты осознаешь это, но признавать и принимать то, что «быть взрослым» оказалось не таким прикольным как хотелосьневероятно тяжело. И всё что хочется, развернуться…   В то время когда ты подросток. Ты в обществе, где все рисуют, тусуются, делают то, что велит непонятная сила вдохновения, не вдаваясь в последствия. “Вокруг меня, всех заботило только однограффити. Оно повсюду, оно везде-всепоглощающая сила”",coverImage:"/images/series/poterunie.jpg",works:[{slug:"ДОФАМИНОВАЯ ЯМА"},{slug:"ТРАГЕДИЯ"},{slug:"ПРЕОДОЛЕНИЕ ПЕРВОГО ПОРОГА"},{slug:"КУСКИ"}]},{slug:"Отголоски присутствия",title:"Отголоски присутствия",description:"Этот триптих — о расслоении времени, о точке, где память и реальность перестают совпадать. Боковые работы — фрагменты утраченного времени, насыщенные цветом, граффити, движением. Здесь юность растворяется в облаках краски, как воспоминание, которое всё ещё пахнет улицей, свободой, дружбой. Эти образы живут на границе сна и реальности, они уже не существуют, но всё ещё дышат внутри сознания. А в центре — тяжесть. Фигура в кресле будто осела под собственным весом — не телесным, а временным. Кресло превращается в подобие надгробия, символ неподвижности и смирения. Перед ним — темнота, вязкая и безмолвная, как взрослая жизнь, где каждый день похож на предыдущий. Это не смерть, но и не жизнь в прежнем смысле — это существование после пика яркости. Взгляд обращён вперёд, но там нет света, только глубина, в которую уходит всё, что когда-то казалось важным. Друзья остались в голове, как отблески красок на боковых работах. Теперь мир вокруг кажется знакомым, но не своим. Всё ещё есть люди, звуки, движение — но без сопричастности. Этот триптих — о моменте, когда внутренний свет сменяется отсветом памяти. Когда взросление ощущается не как рост, а как оседание — тихое, медленное, неизбежное.",coverImage:"/images/series/otgoloski.jpg",works:[{slug:"Отголоски присутствия 1"},{slug:"Отголоски присутствия 2"},{slug:"Отголоски присутствия 3"}]}];function i(s){return g.find(e=>e.slug===s)}export{i as g,g as s};
